class Solution:
    def colorBorder(self, grid, row, col, color):
        # Brute force: flood fill to collect the component, then independently
        # test each component cell for border-ness against the original grid.
        m, n = len(grid), len(grid[0])
        orig = grid[row][col]
        comp = set()
        stack = [(row, col)]
        while stack:
            r, c = stack.pop()
            if (r, c) in comp:
                continue
            if not (0 <= r < m and 0 <= c < n) or grid[r][c] != orig:
                continue
            comp.add((r, c))
            stack.extend([(r + 1, c), (r - 1, c), (r, c + 1), (r, c - 1)])
        border = []
        for (r, c) in comp:
            on_edge = r == 0 or c == 0 or r == m - 1 or c == n - 1
            touches = False
            for dr, dc in ((1, 0), (-1, 0), (0, 1), (0, -1)):
                nr, nc = r + dr, c + dc
                if 0 <= nr < m and 0 <= nc < n and (nr, nc) not in comp:
                    touches = True
            if on_edge or touches:
                border.append((r, c))
        out = [row[:] for row in grid]
        for (r, c) in border:
            out[r][c] = color
        return out

